import { ORDINAL_DATATYPE } from '../../../core/datatype-constants';
import { indexOfRange } from '../legend-event-helpers';
import { isArray } from '../../../utils/zcutils';
import { convertNull } from '../../../core/data-processor/size/convert-null';

function ReverseDataFinder(data, eventType) {
    let manager = this,
        { chart, options } = manager,
        { config, legendInstance } = options,
        { encode, scaleComponent } = legendInstance.meta,
        scale = encode === 'clr' ? scaleComponent.scale : scaleComponent.getScale(),
        val = chart.dataset[encode === 'clr' ? 'getClr' : 'getZ'](data),
        indexScale = encode === 'clr' && chart.axes.clr.indexScale;

    let nullAsOptions = { config, scale, columnKey: chart.dataset.getColumnIdx(encode) };
    val = convertNull(val, nullAsOptions);
    return getData(val, options, { indexScale });
}

function getData(val, options, _) {
    let { config, dataType } = options,
        { ranges } = config,
        { indexScale } = _;

    if (dataType === ORDINAL_DATATYPE) {
        let scale_domain = isArray(ranges[0]) ? ranges.map(_ => _[0]) : ranges;
        return scale_domain.indexOf(val);
    } else if (ranges && ranges.length) {
        if (ranges[0].length === 1 && indexScale) {
            return indexScale(val);
        }
        return indexOfRange(val, ranges);
    } else {
        let point = [val, val];
        point.data = val;
        return point;
    }
}

export { ReverseDataFinder };
